esqlQuery.esql:
// Alert when the Dogtag CA cannot connect to its LDAP backend.
// CA connection failures cause silent cert renewal failures which
// can lead to expired IPA server certificates weeks later.
FROM logs-freeipa.ca_audit-*
| WHERE freeipa.ca.info IS NOT NULL AND freeipa.ca.info LIKE "*Connection refused*"
| STATS failure_count = COUNT(*) BY freeipa.ca.server_host
| WHERE failure_count >= 1
